const tag = 'bulk' + Date.now().toString().slice(-6);
const rows = [
  { item_name: tag + ' rice 1kg', price: 71, stock: 9, unit: 'kg', category: 'Staples', brand: '' },
  { item_name: tag + ' dal 1kg', price: 128, stock: 6, unit: 'kg', category: 'Staples', brand: '' },
  { item_name: tag + ' soap', price: 38, stock: 14, unit: 'pcs', category: 'Home Care', brand: '' },
];
return [{
  json: {
    tag,
    chat_id: '919148969183',
    sheet_url: 'https://docs.google.com/spreadsheets/d/mock-bulk-sheet/edit#gid=0',
    rows,
    test_mode: true,
  },
}];

const seed = $('Seed Inputs').first().json || {};
return [{
  json: {
    chat_id: seed.chat_id,
    message: seed.sheet_url,
    test_sheet_rows: Array.isArray(seed.rows) ? seed.rows : [],
    test_mode: true,
  },
}];

const seed = $('Seed Inputs').first().json || {};
const preview = $('Run Bulk Preview').first().json || {};
const buttons = Array.isArray(preview.buttons) ? preview.buttons : [];
const apply = buttons.find((button) => String(button.id || '').startsWith('owner_bulk_apply__'));
const cancel = buttons.find((button) => String(button.id || '').startsWith('owner_bulk_cancel__'));
return [{
  json: {
    ...seed,
    preview_text: String(preview.body_text || ''),
    apply_id: apply ? String(apply.id) : '',
    cancel_id: cancel ? String(cancel.id) : '',
  },
}];

const d = $('Extract Bulk Apply').first().json || {};
return [{
  json: {
    chat_id: d.chat_id,
    button_id: d.apply_id,
    source_type: 'button',
    test_mode: true,
  },
}];

const extracted = $('Extract Bulk Apply').first().json || {};
const applied = $('Run Bulk Apply').first().json || {};
return [{
  json: {
    tag: extracted.tag || '',
    preview_text: String(extracted.preview_text || ''),
    apply_id: String(extracted.apply_id || ''),
    cancel_id: String(extracted.cancel_id || ''),
    apply_text: String(applied.body_text || ''),
  },
}];
